// Main control coordination logic - processes device data and makes control decisions
const devices = global.get('devices') || {};
const control = global.get('control') || { zeroExportThreshold: 50, loadShareRampRate: 1.0, pvPriority: true };

// Get latest device data
const huawei = devices['Huawei SmartLogger 3000A'] || {};
const gc600 = devices['SICES GC600'] || {};
const mc200 = devices['SICES MC200'] || {};

// Calculate system status
const systemStatus = {
  timestamp: new Date().toISOString(),
  pv_power: parseFloat(huawei.active_power) || 0,
  genset_power: parseFloat(gc600.active_power) || 0,
  grid_power: parseFloat(mc200.active_power_total) || 0,
  is_exporting: mc200.is_exporting || false,
  export_power: mc200.is_exporting ? Math.abs(parseFloat(mc200.active_power_total) || 0) : 0
};

// Control logic decisions
const commands = [];

// Zero Export Logic
if (systemStatus.is_exporting && systemStatus.export_power > control.zeroExportThreshold) {
  const curtailment = Math.min(100, (systemStatus.export_power / systemStatus.pv_power) * 100);
  commands.push({
    device: 'Huawei SmartLogger 3000A',
    action: 'curtail_power',
    value: 100 - curtailment,
    reason: 'Zero export protection'
  });
}

// Load Sharing Logic
const totalLoad = systemStatus.pv_power + systemStatus.genset_power - systemStatus.grid_power;
if (totalLoad > 0 && control.pvPriority) {
  const pvContribution = Math.min(100, (systemStatus.pv_power / totalLoad) * 100);
  const gensetTarget = Math.max(0, 100 - pvContribution);

  if (Math.abs(gensetTarget - (systemStatus.genset_power / totalLoad * 100)) > 5) {
    commands.push({
      device: 'SICES GC600',
      action: 'set_power_setpoint',
      value: gensetTarget,
      reason: 'Load sharing optimization'
    });
  }
}

// Package output
msg.payload = {
  timestamp: systemStatus.timestamp,
  system_status: systemStatus,
  load_sharing: {
    pv_contribution: systemStatus.pv_power > 0 ? (systemStatus.pv_power / (systemStatus.pv_power + systemStatus.genset_power)) * 100 : 0,
    genset_contribution: systemStatus.genset_power > 0 ? (systemStatus.genset_power / (systemStatus.pv_power + systemStatus.genset_power)) * 100 : 0
  },
  commands: commands
};

return msg;

// Dispatch control commands to appropriate devices
const commands = msg.payload.commands || [];

// Process each command
commands.forEach(command => {
  const commandMsg = {
    topic: `control/${command.device.toLowerCase().replace(/\s+/g, '_')}`,
    payload: command,
    timestamp: new Date().toISOString()
  };

  node.send(commandMsg);
});

return null;

// Log control decisions and system status
const data = msg.payload;
const logEntry = {
  timestamp: data.timestamp,
  system_status: data.system_status,
  load_sharing: data.load_sharing,
  commands_issued: data.commands.length,
  commands: data.commands.map(cmd => ({
    device: cmd.device,
    action: cmd.action,
    value: cmd.value,
    reason: cmd.reason
  }))
};

// Store in context for dashboard
const controlHistory = context.get('controlHistory') || [];
controlHistory.push(logEntry);

// Keep only last 100 entries
if (controlHistory.length > 100) {
  controlHistory.shift();
}

context.set('controlHistory', controlHistory);
global.set('lastControlDecision', logEntry);

msg.payload = logEntry;
return msg;

// Log successful/failed write operations
const confirmation = {
  timestamp: new Date().toISOString(),
  device: msg.payload.device || 'unknown',
  success: !msg.error,
  error: msg.error || null,
  address: msg.payload.address,
  value: msg.payload.value
};

// Store confirmation for monitoring
const writeHistory = context.get('writeHistory') || [];
writeHistory.push(confirmation);

if (writeHistory.length > 50) {
  writeHistory.shift();
}

context.set('writeHistory', writeHistory);

msg.payload = confirmation;
return msg;
